// // This module is a 16-bit down counter that decrements its value on each positive clock edge and sets to maximum when a reset signal is asserted.
module counter_8bit (
    input wire clk,
    input wire reset,
    output reg [7:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 8'b0;
        end else begin
            count <= count + 1;
        end
    end
endmodule
